    "static boolean isValidDefineValue(Node val, Set<String> defines) {
    switch (val.getType()) {
      case Token.STRING:
      case Token.NUMBER:
      case Token.TRUE:
      case Token.FALSE:
        return true;

      // Unary operators are valid if the child is valid.
      case Token.NOT:
      case Token.NEG:
      case Token.BITNOT: {
        Node child = val.getFirstChild();
        return child != null && isValidDefineValue(child, defines);
      }

      // Binary operators are only valid if both children are valid.
      case Token.BITAND:
      case Token.BITOR:
      case Token.BITXOR:
      case Token.ADD: {
        Node left = val.getFirstChild();
        Node right = (left != null) ? left.getNext() : null;
        return left != null && right != null
            && isValidDefineValue(left, defines)
            && isValidDefineValue(right, defines);
      }

      // Names are valid if and only if they are defines themselves.
      case Token.NAME:
      case Token.GETPROP:
        if (val.isQualifiedName()) {
          return defines.contains(val.getQualifiedName());
        }
    }
    return false;
  }"
  ],
